import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";

/**
 * Servicio para comunicarse con Gemini.
 * La instancia de GoogleGenAI se crea dentro de la función para evitar que errores
 * de inicialización (como la falta de API_KEY en el entorno de build) bloqueen
 * la carga total de la página.
 */
export const sendMessageToGemini = async (message: string): Promise<string> => {
  try {
    // Obtenemos la API KEY directamente del entorno según las guías
    const apiKey = process.env.API_KEY;

    if (!apiKey) {
      console.warn("API Key no detectada. Asegúrate de configurar las variables de entorno.");
      return "Lo siento, el servicio de asistencia no está disponible en este momento. Por favor, intenta más tarde.";
    }

    const ai = new GoogleGenAI({ apiKey });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: message,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });

    if (!response.text) {
      throw new Error("Respuesta vacía del modelo.");
    }

    return response.text;
  } catch (error) {
    console.error("Error al comunicarse con Gemini:", error);

    // Manejo profesional de errores para el usuario colombiano
    const errorMessage = error instanceof Error ? error.message : String(error);

    if (errorMessage.includes("Requested entity was not found")) {
      return "Hubo un pequeño inconveniente técnico con el servicio de IA. Estamos trabajando para solucionarlo.";
    }

    return "¡Qué pena! Tuvimos un pequeño percance en la cocina central. ¿Podrías intentar preguntarme de nuevo en un momento?";
  }
};

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";

/**
 * Servicio de comunicación con la IA de Empanadas Creativas.
 * Cumple con la normativa de seguridad de usar exclusivamente process.env.API_KEY.
 */
export const sendMessageToGemini = async (message: string): Promise<string> => {
  try {
    const apiKey = process.env.API_KEY;

    // Verificación de seguridad previa a la instanciación para evitar crash en el navegador
    if (!apiKey || apiKey.trim() === "") {
      console.error("Error: La API_KEY no está configurada en las variables de entorno de Vercel.");
      return "¡Hola! Soy tu Sommelier, pero parece que me falta una pizca de configuración técnica para responderte. Por favor, asegúrate de configurar la API_KEY en el panel de Vercel.";
    }

    // Inicialización siguiendo estrictamente las guías de Google GenAI
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: message,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });

    // Retorno directo de la propiedad .text según las especificaciones del SDK
    return response.text || "No logré procesar esa idea, ¿me la repites?";

  } catch (error) {
    console.error("Error en la comunicación con el Sommelier AI:", error);

    // Respuesta amigable y profesional para el usuario
    return "¡Qué pena! Tuvimos un pequeño percance en la cocina central de datos. ¿Podrías intentar preguntarme de nuevo en un momento?";
